66	impl MatchingStatus {
67	    /// Returns true if there exist entities matching the target (i.e., either Subscribers matching Publisher's key expression or Queryables matching Querier's key expression and target).
68	    ///
69	    /// # Examples
70	    /// ```
71	    /// # #[tokio::main]
72	    /// # async fn main() {
73	    ///
74	    /// let session = zenoh::open(zenoh::Config::default()).await.unwrap();
75	    /// let publisher = session.declare_publisher("key/expression").await.unwrap();
76	    /// let matching_subscribers: bool = publisher
77	    ///     .matching_status()
78	    ///     .await
79	    ///     .unwrap()
80	    ///     .matching();
81	    /// # }
82	    /// ```
83	    pub fn matching(&self) -> bool {
84	        self.matching
85	    }
86	}
