97	impl MatchingListenerState {
98	    pub(crate) fn is_matching(&self, key_expr: &KeyExpr, match_type: MatchingStatusType) -> bool {
99	        match match_type {
100	            MatchingStatusType::Subscribers => {
101	                self.match_type == MatchingStatusType::Subscribers
102	                    && self.key_expr.intersects(key_expr)
103	            }
104	            MatchingStatusType::Queryables(false) => {
105	                self.match_type == MatchingStatusType::Queryables(false)
106	                    && self.key_expr.intersects(key_expr)
107	            }
108	            MatchingStatusType::Queryables(true) => {
109	                (self.match_type == MatchingStatusType::Queryables(false)
110	                    && self.key_expr.intersects(key_expr))
111	                    || (self.match_type == MatchingStatusType::Queryables(true)
112	                        && key_expr.includes(&self.key_expr))
113	            }
114	        }
115	    }
116	}
