141	/// # #[tokio::main]
142	/// # async fn main() {
143	///
144	/// let session = zenoh::open(zenoh::Config::default()).await.unwrap();
145	/// let publisher = session.declare_publisher("key/expression").await.unwrap();
146	/// let matching_listener = publisher.matching_listener().await.unwrap();
147	/// while let Ok(matching_status) = matching_listener.recv_async().await {
148	///     if matching_status.matching() {
149	///         println!("Publisher has matching subscribers.");
150	///     } else {
151	///         println!("Publisher has NO MORE matching subscribers.");
152	///     }
153	/// }
154	/// # }
155	/// ```
156	pub struct MatchingListener<Handler> {
