177	    /// # #[tokio::main]
178	    /// # async fn main() {
179	    ///
180	    /// let session = zenoh::open(zenoh::Config::default()).await.unwrap();
181	    /// let publisher = session.declare_publisher("key/expression").await.unwrap();
182	    /// let matching_listener = publisher.matching_listener().await.unwrap();
183	    /// matching_listener.undeclare().await.unwrap();
184	    /// # }
185	    /// ```
186	    #[inline]
187	    pub fn undeclare(self) -> MatchingListenerUndeclaration<Handler>
188	    where
189	        Handler: Send,
190	    {
191	        self.undeclare_inner(())
192	    }
