258	/// A [`Resolvable`] returned by [`MatchingListener::undeclare`]
259	pub struct MatchingListenerUndeclaration<Handler> {
260	    listener: MatchingListener<Handler>,
261	    wait_callbacks: bool,
262	}
263	
264	impl<Handler> fmt::Debug for MatchingListenerUndeclaration<Handler> {
265	    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
