73	/// A publisher that allows sending data through a stream.
74	/// A Publisher is declared by a [`Session`](crate::api::session::Session) for a given key expression
75	/// with method [`Session::declare_publisher`](crate::api::session::Session::declare_publisher).
76	///
77	/// Publishers are automatically undeclared when dropped.
78	///
79	/// # Examples
80	/// ```
81	/// # #[tokio::main]
82	/// # async fn main() {
83	///
84	/// let session = zenoh::open(zenoh::Config::default()).await.unwrap();
85	/// let publisher = session.declare_publisher("key/expression").await.unwrap();
86	/// publisher.put("value").await.unwrap();
87	/// # format!("{publisher:?}");
88	/// # }
89	/// ```
90	///
91	///
92	/// `Publisher` implements the `Sink` trait which is useful for forwarding
93	/// streams to zenoh.
94	/// ```
95	/// # #[tokio::main]
96	/// # async fn main() {
97	/// use futures::StreamExt;
98	///
99	/// let session = zenoh::open(zenoh::Config::default()).await.unwrap();
100	/// let mut subscriber = session.declare_subscriber("key/expression").await.unwrap();
101	/// let publisher = session.declare_publisher("another/key/expression").await.unwrap();
