617	type ProtocolPriority = zenoh_protocol::core::Priority;
618	impl From<Priority> for ProtocolPriority {
619	    fn from(prio: Priority) -> Self {
620	        // The Priority in the prelude differs from the Priority in the core protocol only by
621	        // the missing Control priority. The Control priority is reserved for zenoh's internal use
622	        // and as such it is not exposed by the zenoh API. Nevertheless, the values of the
623	        // priorities which are common to the internal and public Priority enums are the same. Therefore,
624	        // it is possible to safely transmute from the public Priority enum toward the internal
625	        // Priority enum without risking being in an invalid state.
626	        // For better robustness, the correctness of the unsafe transmute operation is covered
627	        // by the unit test below.
628	        unsafe { std::mem::transmute::<Priority, zenoh_protocol::core::Priority>(prio) }
629	    }
630	}
631	
632	impl TryFrom<ProtocolPriority> for Priority {
633	    type Error = zenoh_result::Error;
634	    fn try_from(priority: ProtocolPriority) -> Result<Self, Self::Error> {
635	        match priority {
636	            ProtocolPriority::Control => bail!("'Control' is not a valid priority value."),
637	            ProtocolPriority::RealTime => Ok(Priority::RealTime),
638	            ProtocolPriority::InteractiveHigh => Ok(Priority::InteractiveHigh),
639	            ProtocolPriority::InteractiveLow => Ok(Priority::InteractiveLow),
640	            ProtocolPriority::DataHigh => Ok(Priority::DataHigh),
641	            ProtocolPriority::Data => Ok(Priority::Data),
642	            ProtocolPriority::DataLow => Ok(Priority::DataLow),
643	            ProtocolPriority::Background => Ok(Priority::Background),
644	        }
645	    }
646	}
